    expect(vertexCount(decorated)).toBeGreaterThan(vertexCount(plain) * 1.5);
  });

  it('runs seams parallel to the longer dimension on flat roofs', () => {
    // 8 m × 5 m flat — seams should run along X (the longer side), placed
