  const y = elevM + i * (height / hCount);
  const hm = new THREE.Mesh(new THREE.BoxGeometry(len, MW, thick), mullionMat);
  hm.position.set(sx + dx / 2, y, sz + dz / 2);
  hm.rotation.y = yaw;
  addEdges(hm);
  group.add(hm);
}

