24	function planLocationLineOffsetFrac(loc: WallLocationLine): number {
25	  switch (loc) {
26	    case 'finish-face-exterior':
27	    case 'core-face-exterior':
28	      return 0.5;
29	    case 'finish-face-interior':
30	    case 'core-face-interior':
31	      return -0.5;
32	    default:
33	      return 0;
34	  }
35	}
36	
37	export function planWallMesh(
38	  wall: Extract<Element, { kind: 'wall' }>,
39	  selectedId?: string,
40	  lineWeightScale = 1,
41	  elementsById?: Record<string, Element>,
42	): THREE.Object3D {
43	  const { lenM: len, nx, nz } = segmentDir(wall);
44	
45	  const sx = ux(wall.start.xMm);
46	
47	  const sz = uz(wall.start.yMm);
48	
49	  const angle = Math.atan2(nz, nx);
50	
51	  const thick = THREE.MathUtils.clamp((wall.thicknessMm * lineWeightScale) / 1000, 0.02, 1.8);
52	
53	  const locFrac = planLocationLineOffsetFrac(wall.locationLine ?? 'wall-centerline');
54	  const perpX = -nz * locFrac * thick;
55	  const perpZ = nx * locFrac * thick;
56	
57	  const geom = new THREE.BoxGeometry(len, PLAN_WALL_CENTER_SLICE_HEIGHT_M, thick);
58	
59	  const mat = new THREE.MeshStandardMaterial({
60	    roughness: 0.82,
61	
62	    metalness: 0.02,
63	
64	    color: (() => {
65	      const p = getPlanPalette();
66	      return wall.id === selectedId ? p.wallSelected : p.wallFill;
67	    })(),
68	  });
69	
70	  const mesh = new THREE.Mesh(geom, mat);
71	
72	  mesh.position.set(sx + (nx * len) / 2 + perpX, PLAN_Y, sz + (nz * len) / 2 + perpZ);
73	
74	  mesh.rotation.y = -angle;
75	
76	  mesh.userData.bimPickId = wall.id;
77	
78	  // FL-08: when the wall has a wall_type, overlay layer boundary lines.
79	  if (wall.wallTypeId) {
80	    const lines = buildPlanWallLayerLines(wall, len, sx, sz, nx, nz, elementsById);
81	    if (lines) {
82	      const group = new THREE.Group();
83	      group.userData.bimPickId = wall.id;
84	      group.add(mesh);
85	      group.add(lines);
86	      return group;
87	    }
88	  }
89	
90	  return mesh;
91	}
92	
93	function resolvePlanWallAssembly(
94	  wallTypeId: string,
95	  elementsById?: Record<string, Element>,
96	): {
97	  basisLine: 'center' | 'face_interior' | 'face_exterior';
98	  layers: { thicknessMm: number; materialKey: string }[];
99	} | null {
100	  const builtIn = getBuiltInWallType(wallTypeId);
101	  if (builtIn) {
102	    return {
103	      basisLine: builtIn.basisLine,
104	      layers: builtIn.layers.map((l) => ({
105	        thicknessMm: l.thicknessMm,
106	        materialKey: l.materialKey,
107	      })),
108	    };
109	  }
110	  if (!elementsById) return null;
111	  const el = elementsById[wallTypeId];
112	  if (!el || el.kind !== 'wall_type') return null;
113	  return {
114	    basisLine: (el.basisLine ?? 'center') as 'center' | 'face_interior' | 'face_exterior',
115	    layers: el.layers.map((l) => ({
116	      thicknessMm: Number(l.thicknessMm),
117	      materialKey: String(l.materialKey ?? ''),
118	    })),
119	  };
120	}
121	
122	function buildPlanWallLayerLines(
123	  wall: Extract<Element, { kind: 'wall' }>,
124	  lenM: number,
125	  sx: number,
126	  sz: number,
127	  nx: number,
128	  nz: number,
129	  elementsById?: Record<string, Element>,
130	): THREE.LineSegments | null {
131	  if (!wall.wallTypeId) return null;
132	  const assembly = resolvePlanWallAssembly(wall.wallTypeId, elementsById);
133	  if (!assembly || assembly.layers.length === 0) return null;
134	
135	  const totalThickMm = assembly.layers.reduce((acc, l) => acc + l.thicknessMm, 0);
136	  if (totalThickMm <= 0) return null;
137	
138	  // Wall normal direction (perpendicular to (nx,nz) tangent in plan space).
139	  const perpX = -nz;
140	  const perpZ = nx;
141	
142	  // Plan-space basis offset from wall centerline to the interior face.
143	  let cursorMm: number;
144	  switch (assembly.basisLine) {
145	    case 'face_exterior':
146	      cursorMm = totalThickMm / 2;
147	      break;
148	    case 'face_interior':
149	    case 'center':
150	    default:
151	      cursorMm = -totalThickMm / 2;
152	      break;
153	  }
154	
155	  const positions: number[] = [];
156	  const colors: number[] = [];
157	
158	  // Half-length along the wall axis in metres.
159	  const halfLenM = lenM / 2;
160	  const cxM = sx + (nx * lenM) / 2;
161	  const czM = sz + (nz * lenM) / 2;
162	
163	  // Boundary at the start of the stack:
164	  let prevCursorMm = cursorMm;
165	  for (let i = 0; i < assembly.layers.length; i++) {
166	    const layer = assembly.layers[i]!;
167	    const boundaryMm = prevCursorMm; // line at the top edge of this layer (interior side)
168	    const offM = boundaryMm / 1000;
169	    const ax = cxM + perpX * offM - nx * halfLenM;
170	    const az = czM + perpZ * offM - nz * halfLenM;
171	    const bx = cxM + perpX * offM + nx * halfLenM;
172	    const bz = czM + perpZ * offM + nz * halfLenM;
173	    // Use this layer's colour darkened 30% for the inner boundary line.
174	    const baseHex = materialHexFor(layer.materialKey);
175	    const lineHex = darkenHex(baseHex, 0.3);
176	    const color = new THREE.Color(lineHex);
177	    positions.push(ax, PLAN_Y + 0.005, az, bx, PLAN_Y + 0.005, bz);
178	    colors.push(color.r, color.g, color.b, color.r, color.g, color.b);
179	    prevCursorMm += layer.thicknessMm;
180	  }
181	  // Final boundary at the exterior face:
182	  const offM = prevCursorMm / 1000;
183	  const ax = cxM + perpX * offM - nx * halfLenM;
184	  const az = czM + perpZ * offM - nz * halfLenM;
185	  const bx = cxM + perpX * offM + nx * halfLenM;
